// Two-stage grader. Real signatures — swap the stub bodies for LLM calls in production.
function claimExtractor(answer) {
  return answer.split(/(?<=[.!?])\s+/).map(s => s.trim()).filter(s => s.length > 15);
}
function claimSupported(claim, docs, threshold = 0.35) {
  const claimWords = new Set(tokenize(claim));
  for (const doc of docs) {
    const docWords = new Set(tokenize(doc.content));
    const overlap = intersect(claimWords, docWords).size / claimWords.size;
    if (overlap >= threshold) return { supported: true, evidence: doc.id };
  }
  return { supported: false, evidence: null };
}
function gradeFaithfulness(sample, agentAnswer) {
  const claims = claimExtractor(agentAnswer);
  const verdicts = claims.map(c => ({ text: c, ...claimSupported(c, sample.retrievedDocs) }));
  const supported = verdicts.filter(v => v.supported).length;
  return { score: claims.length ? supported / claims.length : 0, verdicts };
}
